import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';

const STORAGE_KEY = 'mdd_token';

@Injectable({ providedIn: 'root' })
export class TokenService {
  private readonly subject = new BehaviorSubject<string | null>(this.read());

  readonly token$ = this.subject.asObservable();

  getToken(): string | null {
    return this.subject.value;
  }

  setToken(token: string): void {
    localStorage.setItem(STORAGE_KEY, token);
    this.subject.next(token);
  }

  clearToken(): void {
    localStorage.removeItem(STORAGE_KEY);
    this.subject.next(null);
  }

  private read(): string | null {
    try {
      return localStorage.getItem(STORAGE_KEY);
    } catch {
      return null;
    }
  }
}

export const environment = {
  baseUrl: 'http://localhost:3001/api',
  production: false
};

import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { map, Observable } from 'rxjs';
import type { AuthResponse, LoginRequest, RegisterRequest } from '../models/auth.models';
import { TokenService } from './token.service';
import { environment } from '../environments/environment';

@Injectable({ providedIn: 'root' })
export class AuthService {
    // Evite d'injecter HttpClient et TokenService dans le constructeur, car cela peut causer des problèmes de dépendances circulaires.
  private readonly http = inject(HttpClient);
  private baseUrl = environment.baseUrl;
  private readonly tokenSvc = inject(TokenService);

  login(payload: LoginRequest): Observable<void> {
    return this.http
      .post<AuthResponse>(`${this.baseUrl}/auth/login`, payload)
      .pipe(map((res) => this.tokenSvc.setToken(res.token)));
  }

  register(payload: RegisterRequest): Observable<void> {
    return this.http
      .post<AuthResponse>(`${this.baseUrl}/auth/register`, payload)
      .pipe(map((res) => this.tokenSvc.setToken(res.token)));
  }

  logout(): void {
    this.tokenSvc.clearToken();
  }

isLoggedIn(): boolean {
  const token = this.tokenSvc.getToken();

  if (token) {
    return true;
  } else {
    return false;
  }
}
}

import { CommonModule } from '@angular/common';
import { HttpErrorResponse } from '@angular/common/http';
import { Component, inject } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';

import { MatButtonModule } from '@angular/material/button';
import { MatToolbarModule } from '@angular/material/toolbar';
import { MatIconModule } from '@angular/material/icon';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';

import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    ReactiveFormsModule,
    MatButtonModule,
    MatToolbarModule,
    MatIconModule,
    MatFormFieldModule,
    MatInputModule,
  ],
  templateUrl: './login.component.html',
  styleUrl: './login.component.scss',
})
export class LoginComponent {
  private fb = inject(FormBuilder);
  private auth = inject(AuthService);
  private router = inject(Router);

  form = this.fb.nonNullable.group({
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required]],
  });

  error = '';
  isSubmitting = false;

  submit(): void {
    this.error = '';

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    this.isSubmitting = true;

    const payload = this.form.getRawValue(); // { email, password }

    this.auth.login(payload).subscribe({
      next: () => {
        this.isSubmitting = false;
        this.router.navigate(['/articles']);
      },
      error: (err: HttpErrorResponse) => {
        this.isSubmitting = false;
        this.error = (err.error as { message: string }).message; // message backend
      },
    });
  }
}

