import type { ThemeDto } from '../models/theme.models';
import { Observable } from 'rxjs';
import { environment } from '../environments/environment';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private readonly http = inject(HttpClient);
  private baseUrl = environment.baseUrl;

  list(): Observable<ThemeDto[]> {
    return this.http.get<ThemeDto[]>(`${this.baseUrl}/themes`);
  }

  subscribe(themeId: number): Observable<void> {
    return this.http.post<void>(`${this.baseUrl}/themes/${themeId}/subscribe`, null);
  }

  unsubscribe(themeId: number): Observable<void> {
    return this.http.delete<void>(`${this.baseUrl}/themes/${themeId}/subscribe`);
  }
}

import { CommonModule } from '@angular/common';
import { HttpErrorResponse } from '@angular/common/http';
import { Component, inject } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';

import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';

import { HeaderComponent } from '../../components/header/header.component';
import { ThemeService } from '../../services/theme.service';
import { ArticleService } from '../../services/article.service';
import type { ThemeDto } from '../../models/theme.models';

@Component({
  selector: 'app-article-create',
  standalone: true,
  imports: [
    CommonModule,
    HeaderComponent,
    RouterLink,
    MatButtonModule,
    MatFormFieldModule,
    MatIconModule,
    MatInputModule,
    MatSelectModule,
    ReactiveFormsModule,
  ],
  templateUrl: './article-create.component.html',
  styleUrl: './article-create.component.scss',
})
export class ArticleCreateComponent {
  private fb = inject(FormBuilder);
  private themesApi = inject(ThemeService);
  private articlesApi = inject(ArticleService);
  private router = inject(Router);

  themes: ThemeDto[] = [];
  isLoadingThemes = false;

  form = this.fb.nonNullable.group({
    themeId: [null as number | null, [Validators.required]],
    title: ['', [Validators.required, Validators.maxLength(255)]],
    description: ['', [Validators.required, Validators.maxLength(2000)]],
  });

  isSubmitting = false;
  error = '';

  ngOnInit(): void {
    this.loadThemes();
  }

  submit(): void {
    this.error = '';

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    if (this.isSubmitting) return;

    this.isSubmitting = true;

    const { themeId, title, description } = this.form.getRawValue();

    this.articlesApi.create({ themeId: themeId!, title, description }).subscribe({
      next: (created) => {
        this.isSubmitting = false;
        this.router.navigate(['/articles', created.id]);
      },
      error: (err: HttpErrorResponse) => {
        this.isSubmitting = false;
        this.error = (err.error as { message: string }).message; // message backend
      },
    });
  }

  private loadThemes(): void {
    this.isLoadingThemes = true;
    this.error = '';

    this.themesApi.list().subscribe({
      next: (items) => {
        this.themes = items;
        this.isLoadingThemes = false;
      },
      error: (err: HttpErrorResponse) => {
        this.isLoadingThemes = false;
        this.error = (err.error as { message: string }).message; // message backend
      },
    });
  }
}

import { CommonModule } from '@angular/common';
import { HttpErrorResponse } from '@angular/common/http';
import { Component, inject } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { ActivatedRoute, RouterLink } from '@angular/router';

import { MatButtonModule } from '@angular/material/button';
import { MatDividerModule } from '@angular/material/divider';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';

import { HeaderComponent } from '../../components/header/header.component';
import { ArticleService } from '../../services/article.service';
import type { ArticleDto } from '../../models/article.models';

@Component({
  selector: 'app-article-detail',
  standalone: true,
  imports: [
    CommonModule,
    HeaderComponent,
    RouterLink,
    MatButtonModule,
    MatDividerModule,
    MatFormFieldModule,
    MatIconModule,
    MatInputModule,
    ReactiveFormsModule,
  ],
  templateUrl: './article-detail.component.html',
  styleUrl: './article-detail.component.scss',
})
export class ArticleDetailComponent {
  private route = inject(ActivatedRoute);
  private api = inject(ArticleService);
  private fb = inject(FormBuilder);

  article: ArticleDto | null = null;
  isLoading = false;
  error = '';

  commentForm = this.fb.nonNullable.group({
    description: ['', [Validators.required, Validators.maxLength(2000)]],
  });

  isSending = false;

  private articleId = Number(this.route.snapshot.paramMap.get('id'));

  ngOnInit(): void {
    this.load();
  }

  sendComment(): void {
    this.error = '';

    if (this.commentForm.invalid) {
      this.commentForm.markAllAsTouched();
      return;
    }
    if (this.isSending) return;

    this.isSending = true;
    const { description } = this.commentForm.getRawValue();

    this.api.addComment(this.articleId, { description }).subscribe({
      next: (comment) => {
        this.isSending = false;
        this.commentForm.reset();

        if (this.article) {
          this.article = {
            ...this.article,
            comments: [...(this.article.comments ?? []), comment],
          };
        } else {
          this.load();
        }
      },
      error: (err: HttpErrorResponse) => {
        this.isSending = false;
        this.error = (err.error as { message: string }).message; // message backend
      },
    });
  }

  private load(): void {
    this.isLoading = true;
    this.error = '';

    this.api.getById(this.articleId).subscribe({
      next: (a) => {
        this.article = a;
        this.isLoading = false;
      },
      error: (err: HttpErrorResponse) => {
        this.isLoading = false;
        this.error = (err.error as { message: string }).message; // message backend
      },
    });
  }
}

import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import type { SubscriptionDto } from '../models/subscription.models';
import type { UpdateUserRequest, UserDto } from '../models/user.models';
import { Observable } from 'rxjs';
import { environment } from '../environments/environment';

@Injectable({ providedIn: 'root' })
export class MeService {
  private readonly http = inject(HttpClient);
  private baseUrl = environment.baseUrl;

  getMe(): Observable<UserDto> {
    return this.http.get<UserDto>(`${this.baseUrl}/me`);
  }

  updateMe(payload: UpdateUserRequest): Observable<UserDto> {
    return this.http.put<UserDto>(`${this.baseUrl}/me`, payload);
  }

  subscriptions(): Observable<SubscriptionDto[]> {
    return this.http.get<SubscriptionDto[]>(`${this.baseUrl}/me/subscriptions`);
  }
}

import { CommonModule } from '@angular/common';
import { HttpErrorResponse } from '@angular/common/http';
import { Component, inject } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatDividerModule } from '@angular/material/divider';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatCardModule } from '@angular/material/card';

import { HeaderComponent } from '../../components/header/header.component';
import { MeService } from '../../services/me.service';
import { ThemeService } from '../../services/theme.service';
import type { ThemeDto } from '../../models/theme.models';
import type { UserDto } from '../../models/user.models';

@Component({
  selector: 'app-me',
  standalone: true,
  imports: [
    CommonModule,
    HeaderComponent,
    MatDividerModule,
    MatFormFieldModule,
    MatInputModule,
    MatCardModule,
    ReactiveFormsModule,
  ],
  templateUrl: './me.component.html',
  styleUrl: './me.component.scss',
})
export class MeComponent {
  private meApi = inject(MeService);
  private themesApi = inject(ThemeService);
  private fb = inject(FormBuilder);

  me: UserDto | null = null;
  subscriptions: ThemeDto[] = [];

  private readonly passwordRegex =
    /^(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/;

  form = this.fb.nonNullable.group({
    name: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(255)]],
    email: ['', [Validators.required, Validators.email, Validators.maxLength(255)]],
    password: ['', [Validators.required, Validators.pattern(this.passwordRegex)]],
  });

  isSaving = false;
  error = '';
  success = '';

  ngOnInit(): void {
    this.loadMe();
    this.loadSubscriptions();
  }

  save(): void {
    this.error = '';
    this.success = '';

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    if (this.isSaving) return;

    this.isSaving = true;
    const { name, email, password } = this.form.getRawValue();

    this.meApi.updateMe({ name, email, password }).subscribe({
      next: (updated) => {
        this.isSaving = false;
        this.me = updated;
        this.form.patchValue({ password: '' });
        this.success = 'Profil mis à jour.';
      },
      error: (err: HttpErrorResponse) => {
        this.isSaving = false;
        this.error = (err.error as { message: string }).message;
      },
    });
  }

  unsubscribe(theme: ThemeDto): void {
    this.error = '';
    this.success = '';

    this.themesApi.unsubscribe(theme.id).subscribe({
      next: () => this.loadSubscriptions(),
      error: (err: HttpErrorResponse) => {
        this.error = (err.error as { message: string }).message;
      },
    });
  }

  private loadMe(): void {
    this.error = '';
    this.success = '';

    this.meApi.getMe().subscribe({
      next: (me) => {
        this.me = me;
        this.form.patchValue({ name: me.name, email: me.email });
      },
      error: (err: HttpErrorResponse) => {
        this.error = (err.error as { message: string }).message;
      },
    });
  }

  private loadSubscriptions(): void {
    this.error = '';
    this.success = '';

    this.themesApi.list().subscribe({
      next: (themes) => (this.subscriptions = themes.filter((theme) => theme.subscribed)),
      error: (err: HttpErrorResponse) => {
        this.error = (err.error as { message: string }).message;
      },
    });
  }
}
<app-header></app-header>

<main class="container page">
  <div class="detail-top">
    <h1 class="detail-top__title">Profil utilisateur</h1>
  </div>

  <section class="profile">
    <div class="profile__content">
      <section class="create">
        <form class="create-form" [formGroup]="form" (ngSubmit)="save()">
          <mat-form-field appearance="outline" class="full">
            <mat-label>Username</mat-label>
            <input matInput type="text" formControlName="name" />

            @if (form.controls.name.touched && form.controls.name.invalid) {
              <mat-error>Nom requis (2 caractères minimum).</mat-error>
            }
          </mat-form-field>

          <mat-form-field appearance="outline" class="full">
            <mat-label>E-mail</mat-label>
            <input matInput type="email" formControlName="email" />

            @if (form.controls.email.touched && form.controls.email.invalid) {
              <mat-error>Adresse e-mail invalide.</mat-error>
            }
          </mat-form-field>

          <mat-form-field appearance="outline" class="full">
            <mat-label>Mot de passe</mat-label>
            <input matInput type="password" formControlName="password" />

            @if (form.controls.password.touched && form.controls.password.invalid) {
              <mat-error>8 caractères min., 1 majuscule, 1 chiffre, 1 caractère spécial.</mat-error>
            }
          </mat-form-field>

          <div class="actions form-actions">
            <button class="mdd-button" type="submit" [disabled]="form.invalid || isSaving">
              Sauvegarder
            </button>
          </div>

          @if (error) {
            <mat-error>{{ error }}</mat-error>
          }

          @if (success) {
            <p>{{ success }}</p>
          }
        </form>
      </section>

      <mat-divider class="divider"></mat-divider>

      <h2 class="h2">Abonnements</h2>

      <section class="grid subs" aria-label="Liste des thèmes">
        @if (subscriptions.length === 0) {
          <p>Aucun abonnement.</p>
        }

        @for (theme of subscriptions; track theme.id) {
          <mat-card class="themes-card">
            <mat-card-title>{{ theme.title }}</mat-card-title>
            <p>{{ theme.description }}</p>
            <div class="actions card-actions">
              <button class="mdd-button" type="button" (click)="unsubscribe(theme)">
                Se désabonner
              </button>
            </div>
          </mat-card>
        }
      </section>
    </div>
  </section>
</main>

import { CommonModule } from '@angular/common';
import { HttpErrorResponse } from '@angular/common/http';
import { Component, inject } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatCardModule } from '@angular/material/card';

import { HeaderComponent } from '../../components/header/header.component';
import { ThemeService } from '../../services/theme.service';
import type { ThemeDto } from '../../models/theme.models';

@Component({
  selector: 'app-themes',
  standalone: true,
  imports: [
    CommonModule,
    HeaderComponent,
    MatButtonModule,
    MatCardModule,
  ],
  templateUrl: './themes.component.html',
  styleUrl: './themes.component.scss',
})
export class ThemesComponent {
  private themesApi = inject(ThemeService);

  themes: ThemeDto[] = [];
  isLoading = false;
  error = '';

  ngOnInit(): void {
    this.load();
  }

  subscribe(theme: ThemeDto): void {
    if (theme.subscribed) return;

    this.error = '';
    this.isLoading = true;

    this.themesApi.subscribe(theme.id).subscribe({
      next: () => this.load(),
      error: (err: HttpErrorResponse) => {
        this.isLoading = false;
        this.error = (err.error as { message: string }).message;
      },
    });
  }

  private load(): void {
    this.isLoading = true;
    this.error = '';

    this.themesApi.list().subscribe({
      next: (items) => {
        this.themes = items;
        this.isLoading = false;
      },
